const formItem = $input.first();

const binary = formItem.binary || {};

const resumeKeys = Object.keys(binary).filter((key) =>
	key === 'Resumes' ||
	key.startsWith('Resumes_') ||
	key.startsWith('Resumes.')
);

if (resumeKeys.length === 0) {
	throw new Error('No resume PDFs were uploaded.');
}

return resumeKeys.map((key) => {
	const file = binary[key];

	const index = Number(key.replace('Resumes_', ''));

	return {
		json: {
			fileName: formItem.json.Resumes[index].filename,
		},
		binary: {
			resume: file,
		},
	};
});

// 1. Grab the Job Description vector
const jdEmbedding = $('Create Job Description Embedding').first().json.embedding.values;

// 2. Define the Cosine Similarity math engine
function cosineSimilarity(a, b) {
	let dot = 0;
	let normA = 0;
	let normB = 0;

	for (let i = 0; i < a.length; i++) {
		dot += a[i] * b[i];
		normA += a[i] * a[i];
		normB += b[i] * b[i];
	}

	return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

// 3. Map through the parallel resume items and calculate their scores
const rankedItems = $input.all().map((item, index) => {
	const resumeEmbedding = item.json.embedding.values;
	const fileName = $('Split Resume PDFs').all()[index].binary.resume.fileName;

	return {
		json: {
			fileName,
			score: cosineSimilarity(jdEmbedding, resumeEmbedding),
		},
	};
});

// 4. Sort the array from highest similarity score to lowest
rankedItems.sort((a, b) => b.json.score - a.json.score);

// 5. Output the cleanly indexed final rankings
return rankedItems.map((item, index) => ({
	json: {
		rank: index + 1,
		fileName: item.json.fileName,
		score: item.json.score,
	},
}));
